{
  "intent_summary": "Show weekly trend of Rytelo sales volume over the most recent 52 weeks of available data at the campus level.",
  "tables": ["data_867"],
  "filters": [
    {
      "column": "week_end_date",
      "operator": ">=",
      "value": "derived:rolling_window_52_weeks_from_max_week_end_date"
    },
    {
      "column": "week_end_date",
      "operator": "<=",
      "value": "derived:max_week_end_date"
    }
  ],
  "aggregations": [
    {
      "metric_name": "weekly_sales_mg",
      "function": "SUM",
      "column": "rytelo_total_mg",
      "group_level": "week_end_date"
    }
  ],
  "subqueries": [
    {
      "name": "max_week_end_date_cte",
      "purpose": "Identify the most recent week_end_date in the dataset to anchor the rolling 52-week window.",
      "logic": "Compute MAX(week_end_date) from data_867."
    },
    {
      "name": "rolling_52_weeks_window",
      "purpose": "Derive the start date for the most recent 52-week window based on the maximum week_end_date.",
      "logic": "Define window start as (max_week_end_date - 51 weeks) and window end as max_week_end_date."
    }
  ],
  "group_by": ["week_end_date"],
  "order_by": [
    {
      "column": "week_end_date",
      "direction": "ASC"
    }
  ],
  "limit": null,
  "final_output": {
    "columns": ["week_end_date", "weekly_sales_mg"],
    "row_granularity": "per_group"
  },
  "validation_rules": [
    "Default time period to the most recent 52 weeks when not specified.",
    "Use week_end_date for weekly trend calculations (not date).",
    "Rolling window must be anchored to MAX(week_end_date) derived from the data; do not use system date.",
    "Use rytelo_total_mg (not total_sls) since the question is about Rytelo sales trending without market share/competitor context.",
    "Keep aggregation at campus entity level by not grouping or rolling up to parent fields unless explicitly requested."
  ]
}

{
  "intent_summary": "Show how Rytelo sales performance has changed over the most recent 52 weeks by reporting weekly total Rytelo sales volume and week-over-week growth percentages, aggregated at the campus level and rolled up to an overall (national) weekly trend.",
  "tables": ["data_867"],
  "filters": [
    {
      "column": "week_end_date",
      "operator": ">=",
      "value": "derived:rolling_window_52_weeks_from_max_week_end_date"
    },
    {
      "column": "week_end_date",
      "operator": "<=",
      "value": "derived:max_week_end_date"
    }
  ],
  "aggregations": [
    {
      "metric_name": "weekly_sales",
      "function": "SUM",
      "column": "rytelo_total_mg",
      "group_level": "week_end_date"
    }
  ],
  "subqueries": [
    {
      "name": "max_week_end_date_cte",
      "purpose": "Identify the most recent week_end_date available to anchor the rolling 52-week window.",
      "logic": "Compute MAX(week_end_date) from data_867."
    },
    {
      "name": "weekly_sales_cte",
      "purpose": "Compute total weekly sales volume for each week in the last 52 weeks.",
      "logic": "Filter data_867 to week_end_date between (max_week_end_date - 51 weeks) and max_week_end_date, then aggregate SUM(rytelo_total_mg) grouped by week_end_date."
    },
    {
      "name": "weekly_wow_growth_cte",
      "purpose": "Compute week-over-week growth (%) for the weekly sales series, with special handling when prior week is 0.",
      "logic": "For each week_end_date in weekly_sales_cte, join to the prior week_end_date record to get prior_weekly_sales. Compute growth as: if prior_weekly_sales = 0 and weekly_sales > 0 then 100; else if prior_weekly_sales = 0 and weekly_sales = 0 then 0; else ((weekly_sales - prior_weekly_sales) / prior_weekly_sales) * 100. Convert the growth result to an integer and format with a trailing '%'. Also convert weekly_sales to integer (already INT via SUM of INT) before output."
    }
  ],
  "group_by": ["week_end_date"],
  "order_by": [
    {
      "column": "week_end_date",
      "direction": "ASC"
    }
  ],
  "limit": null,
  "final_output": {
    "columns": ["week_end_date", "weekly_sales", "weekly_sales_wow_growth%"],
    "row_granularity": "per_group"
  },
  "validation_rules": [
    "Default time period to the most recent 52 weeks of available data when not specified.",
    "Use week_end_date for all weekly calculations and rolling weekly windows.",
    "Derive the rolling 52-week window relative to MAX(week_end_date); do not use system date.",
    "Use rytelo_total_mg (not total_sls) because this is a Rytelo-only sales performance question, not market share or competitor comparison.",
    "Aggregate at campus entity level by default; do not substitute parent entities. Summing across all campus entities produces the overall (national) trend.",
    "All growth metrics must be expressed as integer percentages and include a trailing '%'.",
    "Whenever a growth metric is reported, include the corresponding absolute volume (weekly_sales) for the same time grain.",
    "For growth: if prior period value is 0 and current period value > 0, report growth as 100%.",
    "All computations related to growth must be converted to integers (no decimals) before reporting."
  ]
}

{
  "intent_summary": "Assess whether national Rytelo performance is improving by comparing recent 13 weeks vs prior 13 weeks (weekly-average normalized) and include absolute volumes for both periods plus growth percent.",
  "tables": ["data_867"],
  "filters": [
    {
      "column": "week_end_date",
      "operator": ">=",
      "value": "derived:rolling_window_26_weeks_from_max_week_end_date"
    }
  ],
  "aggregations": [
    {
      "metric_name": "sales_r13w_weekly_avg",
      "function": "AVG",
      "column": "rytelo_total_mg",
      "group_level": "none"
    },
    {
      "metric_name": "sales_p13w_weekly_avg",
      "function": "AVG",
      "column": "rytelo_total_mg",
      "group_level": "none"
    },
    {
      "metric_name": "sales_r13w",
      "function": "SUM",
      "column": "rytelo_total_mg",
      "group_level": "none"
    },
    {
      "metric_name": "sales_p13w",
      "function": "SUM",
      "column": "rytelo_total_mg",
      "group_level": "none"
    }
  ],
  "subqueries": [
    {
      "name": "max_week_end_date_cte",
      "purpose": "Identify the most recent week_end_date to anchor rolling windows.",
      "logic": "Compute MAX(week_end_date) from data_867."
    },
    {
      "name": "windowed_weeks_cte",
      "purpose": "Create two comparable 13-week periods (R13W and P13W) relative to the max week_end_date.",
      "logic": "Using max_week_end_date, assign each row to a period label: R13W if week_end_date is within the most recent 13 weeks (inclusive), P13W if within the 13 weeks immediately preceding R13W; exclude all other rows. Aggregate by week_end_date first to produce weekly sums of rytelo_total_mg, then compute period-level SUM and weekly AVG from those weekly sums."
    },
    {
      "name": "growth_calc_cte",
      "purpose": "Compute growth percent between R13W and P13W using weekly averages and enforce edge-case rules.",
      "logic": "Compute growth_percent = ((sales_r13w_weekly_avg - sales_p13w_weekly_avg) / sales_p13w_weekly_avg) * 100; if sales_p13w_weekly_avg = 0 and sales_r13w_weekly_avg > 0 then growth_percent = 100; if both are 0 then growth_percent = 0. Convert growth_percent and all sales metrics to integers (no decimals) before output and append '%' to the growth metric label/value formatting."
    }
  ],
  "group_by": [],
  "order_by": [],
  "limit": null,
  "final_output": {
    "columns": [
      "sales_r13w",
      "sales_p13w",
      "sales_r13w_weekly_avg",
      "sales_p13w_weekly_avg",
      "growth_r13w_vs_p13w%"
    ],
    "row_granularity": "single_row"
  },
  "validation_rules": [
    "Nation must be computed as a full-table rollup with no campus/parent grouping (national-level metrics included in output).",
    "Because a growth comparison is requested without a timeframe, default to R13W vs P13W.",
    "Use week_end_date (not date) for weekly time logic and rolling-window boundaries.",
    "Rolling windows must be anchored to MAX(week_end_date) derived from the table; do not use system date.",
    "Ensure the two compared periods are equal length (13 weeks each); if period lengths differ due to missing weeks, compute growth using weekly averages derived from weekly aggregated totals.",
    "Use rytelo_total_mg (not total_sls) since the question is focused solely on Rytelo and not market share/competitors.",
    "Always accompany growth with corresponding absolute volume values for both periods.",
    "All growth metrics must be expressed as a percentage with a '%' sign.",
    "If previous period value is 0 and current period value is > 0, report growth as 100%.",
    "All computations related to growth, decline, and weekly averages must be converted to integers (no decimals) before reporting results."
  ]
}

{
  "intent_summary": "Assess short-term sales momentum for Rytelo by comparing recent 4-week performance vs the prior 4-week period using weekly-average normalization and reporting both absolute volume and growth percent.",
  "tables": ["data_867"],
  "filters": [
    {
      "column": "week_end_date",
      "operator": ">=",
      "value": "derived:rolling_window_8_weeks_from_max_week_end_date"
    },
    {
      "column": "week_end_date",
      "operator": "<=",
      "value": "derived:max_week_end_date"
    }
  ],
  "aggregations": [
    {
      "metric_name": "weekly_sales_mg_r4w",
      "function": "AVG",
      "column": "rytelo_total_mg",
      "group_level": "week_end_date"
    },
    {
      "metric_name": "weekly_sales_mg_p4w",
      "function": "AVG",
      "column": "rytelo_total_mg",
      "group_level": "week_end_date"
    },
    {
      "metric_name": "sales_mg_r4w",
      "function": "SUM",
      "column": "rytelo_total_mg",
      "group_level": "none"
    },
    {
      "metric_name": "sales_mg_p4w",
      "function": "SUM",
      "column": "rytelo_total_mg",
      "group_level": "none"
    }
  ],
  "subqueries": [
    {
      "name": "max_week_end_date_cte",
      "purpose": "Identify the most recent complete week in the dataset for rolling weekly windows.",
      "logic": "Compute MAX(week_end_date) as max_week_end_date from data_867."
    },
    {
      "name": "weekly_totals_cte",
      "purpose": "Aggregate shipments to weekly totals to enable 4-week vs prior-4-week comparisons on equal-length periods and weekly-average calculations.",
      "logic": "Group data_867 by week_end_date and compute SUM(rytelo_total_mg) as weekly_sales_mg for all weeks between (max_week_end_date - 7 weeks) and max_week_end_date inclusive."
    },
    {
      "name": "window_splits_cte",
      "purpose": "Split weekly totals into Recent 4 Weeks (R4W) and Prior 4 Weeks (P4W) relative to max_week_end_date.",
      "logic": "Using weekly_totals_cte: define R4W as week_end_date in (max_week_end_date - 3 weeks) through max_week_end_date; define P4W as week_end_date in (max_week_end_date - 7 weeks) through (max_week_end_date - 4 weeks)."
    },
    {
      "name": "momentum_metrics_cte",
      "purpose": "Compute absolute and percentage momentum metrics with required integer rounding and zero-baseline growth handling.",
      "logic": "From window_splits_cte compute: sales_mg_r4w = SUM(weekly_sales_mg) over R4W; sales_mg_p4w = SUM(weekly_sales_mg) over P4W; weekly_avg_sales_mg_r4w = (sales_mg_r4w / 4); weekly_avg_sales_mg_p4w = (sales_mg_p4w / 4); momentum_growth_r4w_vs_p4w = CASE WHEN weekly_avg_sales_mg_p4w = 0 AND weekly_avg_sales_mg_r4w > 0 THEN 100 WHEN weekly_avg_sales_mg_p4w = 0 AND weekly_avg_sales_mg_r4w = 0 THEN 0 ELSE ((weekly_avg_sales_mg_r4w - weekly_avg_sales_mg_p4w) / weekly_avg_sales_mg_p4w) * 100 END. Convert all computed metrics (weekly avgs and sales) to integers (no decimals) before output; append '%' to growth metric label/value."
    }
  ],
  "group_by": [],
  "order_by": [],
  "limit": null,
  "final_output": {
    "columns": [
      "max_week_end_date",
      "sales_mg_r4w",
      "sales_mg_p4w",
      "weekly_avg_sales_mg_r4w",
      "weekly_avg_sales_mg_p4w",
      "momentum_growth_r4w_vs_p4w_%"
    ],
    "row_granularity": "single_row"
  },
  "validation_rules": [
    "Use data_867 only (Rytelo-focused); use rytelo_total_mg as the sales volume metric.",
    "Short-term momentum must be evaluated on a 4-week window; compare R4W vs P4W.",
    "Rolling windows must be calculated relative to MAX(week_end_date); do not use system date.",
    "Use week_end_date for all weekly calculations.",
    "Because periods are equal length (4 weeks vs 4 weeks), weekly-average normalization is still required and must be used as the basis for growth calculation.",
    "All computations related to growth and weekly averages must be converted to integers (no decimals) before reporting.",
    "All growth metrics must be expressed in percentage (%) format and must include '%' in the output label/value.",
    "If prior-period weekly average is 0 and current-period weekly average > 0, growth must be reported as 100%.",
    "Always accompany the growth metric with the corresponding absolute volume values for both periods (sales_mg_r4w and sales_mg_p4w).",
    "Default entity level is campus; do not aggregate to parent (no parent_id grouping).",
    "If any weeks are missing within the 8-week window, compute weekly totals only for available week_end_date values, but still divide by 4 for weekly averages to preserve deterministic 4-week window definitions."
  ]
}

{
  "intent_summary": "Summarize Rytelo sales performance for the most recent month available in the data, including current month sales volume and month-over-month growth versus the immediately prior month (normalized to weekly averages because month lengths may differ), at the campus level rolled up to a national total.",
  "tables": ["data_867"],
  "filters": [
    {
      "column": "date",
      "operator": ">=",
      "value": "derived:start_of_recent_month_from_max_date"
    },
    {
      "column": "date",
      "operator": "<=",
      "value": "derived:max_date"
    }
  ],
  "aggregations": [
    {
      "metric_name": "sales_recent_month_mg",
      "function": "SUM",
      "column": "rytelo_total_mg",
      "group_level": "none"
    },
    {
      "metric_name": "sales_recent_month_sls",
      "function": "SUM",
      "column": "rytelo_total_sls",
      "group_level": "none"
    },
    {
      "metric_name": "weekly_avg_sales_recent_month_mg",
      "function": "AVG",
      "column": "derived:weekly_sum_rytelo_total_mg_recent_month",
      "group_level": "none"
    },
    {
      "metric_name": "weekly_avg_sales_prior_month_mg",
      "function": "AVG",
      "column": "derived:weekly_sum_rytelo_total_mg_prior_month",
      "group_level": "none"
    },
    {
      "metric_name": "growth_recent_month_vs_prior_month_mg",
      "function": "AVG",
      "column": "derived:growth_percent_weekly_avg_mg_recent_vs_prior_month",
      "group_level": "none"
    }
  ],
  "subqueries": [
    {
      "name": "max_date_cte",
      "purpose": "Identify the most recent transaction date in the dataset to anchor the 'recent month' window.",
      "logic": "Compute MAX(date) from data_867; treat as derived:max_date."
    },
    {
      "name": "recent_month_bounds_cte",
      "purpose": "Derive the start and end dates for the most recent month present in the data.",
      "logic": "Using derived:max_date, derive the month period that contains it; start = first day of that month, end = derived:max_date (do not extend beyond available data)."
    },
    {
      "name": "prior_month_bounds_cte",
      "purpose": "Derive the start and end dates for the month immediately preceding the recent month.",
      "logic": "Using derived:start_of_recent_month_from_max_date, prior month start = first day of previous month; prior month end = last day of previous month (or max available date within that month if data is incomplete)."
    },
    {
      "name": "recent_month_weekly_sums_cte",
      "purpose": "Create weekly totals within the recent month to enable weekly-average normalization.",
      "logic": "Filter data_867 to recent month bounds; group by week_end_date; compute SUM(rytelo_total_mg) as derived:weekly_sum_rytelo_total_mg_recent_month."
    },
    {
      "name": "prior_month_weekly_sums_cte",
      "purpose": "Create weekly totals within the prior month to enable weekly-average normalization.",
      "logic": "Filter data_867 to prior month bounds; group by week_end_date; compute SUM(rytelo_total_mg) as derived:weekly_sum_rytelo_total_mg_prior_month."
    },
    {
      "name": "weekly_avg_and_growth_cte",
      "purpose": "Compute weekly average mg for both months and the growth percent using weekly averages (normalization), applying the special rule when prior equals 0.",
      "logic": "Compute AVG(derived:weekly_sum_rytelo_total_mg_recent_month) and AVG(derived:weekly_sum_rytelo_total_mg_prior_month). Growth% = if prior_avg = 0 and recent_avg > 0 then 100 else ((recent_avg - prior_avg)/prior_avg)*100. Express as percent and later cast to integer."
    }
  ],
  "group_by": [],
  "order_by": [],
  "limit": null,
  "final_output": {
    "columns": [
      "sales_recent_month_mg",
      "sales_recent_month_sls",
      "weekly_avg_sales_recent_month_mg",
      "weekly_avg_sales_prior_month_mg",
      "growth_recent_month_vs_prior_month_mg"
    ],
    "row_granularity": "single_row"
  },
  "validation_rules": [
    "Use only data_867 for this Rytelo-only sales performance request (do not use total_sls or competitor table).",
    "Derive derived:max_date using a subquery MAX(date); do not use system date.",
    "Recent month must be the calendar month that contains derived:max_date; do not assume the current calendar month.",
    "Because months can be unequal length, compute growth using weekly averages (weekly sums averaged within each month) before comparison.",
    "All growth metrics must be expressed as percentage with a '%' sign in the final presentation layer.",
    "If prior period weekly average is 0 and recent period weekly average > 0, set growth to 100%.",
    "Always accompany growth with the corresponding absolute volume metric (include sales_recent_month_mg).",
    "Convert growth and weekly-average outputs to integers (no decimals) before reporting.",
    "Default aggregation level is campus; since no campus breakdown is requested, return a national total in a single row."
  ]
}

{
  "intent_summary": "Summarize Rytelo sales performance for the most recent month available in the data, including total sales volume (mg and sales $) for that month and month-over-month growth versus the immediately prior month, with growth normalized using weekly averages (based on week_end_date) to account for unequal month lengths; report as a single national row.",
  "tables": ["data_867"],
  "filters": [
    {
      "column": "date",
      "operator": ">=",
      "value": "derived:start_of_recent_month_from_max_date"
    },
    {
      "column": "date",
      "operator": "<=",
      "value": "derived:max_date"
    }
  ],
  "aggregations": [
    {
      "metric_name": "sales_recent_month_mg",
      "function": "SUM",
      "column": "rytelo_total_mg",
      "group_level": "none"
    },
    {
      "metric_name": "sales_recent_month_sls",
      "function": "SUM",
      "column": "rytelo_total_sls",
      "group_level": "none"
    },
    {
      "metric_name": "weekly_avg_sales_recent_month_mg",
      "function": "AVG",
      "column": "derived:weekly_sum_rytelo_total_mg_recent_month",
      "group_level": "none"
    },
    {
      "metric_name": "weekly_avg_sales_prior_month_mg",
      "function": "AVG",
      "column": "derived:weekly_sum_rytelo_total_mg_prior_month",
      "group_level": "none"
    },
    {
      "metric_name": "growth_recent_month_vs_prior_month_mg",
      "function": "AVG",
      "column": "derived:growth_percent_weekly_avg_mg_recent_vs_prior_month",
      "group_level": "none"
    }
  ],
  "subqueries": [
    {
      "name": "max_date_cte",
      "purpose": "Identify the most recent transaction date in the dataset to anchor the 'recent month' window.",
      "logic": "Compute MAX(date) from data_867; treat as derived:max_date."
    },
    {
      "name": "recent_month_bounds_cte",
      "purpose": "Derive the start and end dates for the most recent month present in the data.",
      "logic": "Using derived:max_date, derive the calendar month that contains it; derived:start_of_recent_month_from_max_date = first day of that month; derived:end_of_recent_month_in_data = derived:max_date (do not extend beyond available data)."
    },
    {
      "name": "prior_month_bounds_cte",
      "purpose": "Derive the start and end dates for the month immediately preceding the recent month.",
      "logic": "Using derived:start_of_recent_month_from_max_date, derived:start_of_prior_month = first day of the previous calendar month; derived:end_of_prior_month = last day of the previous calendar month (if the dataset has no rows for part of that month, the effective data-covered end is simply the max available date within that month, but the filter must not go beyond that month)."
    },
    {
      "name": "recent_month_weekly_sums_cte",
      "purpose": "Create weekly totals within the recent month to enable weekly-average normalization.",
      "logic": "Filter data_867 where date between derived:start_of_recent_month_from_max_date and derived:end_of_recent_month_in_data; group by week_end_date; compute SUM(rytelo_total_mg) as derived:weekly_sum_rytelo_total_mg_recent_month."
    },
    {
      "name": "prior_month_weekly_sums_cte",
      "purpose": "Create weekly totals within the prior month to enable weekly-average normalization.",
      "logic": "Filter data_867 where date between derived:start_of_prior_month and derived:end_of_prior_month; group by week_end_date; compute SUM(rytelo_total_mg) as derived:weekly_sum_rytelo_total_mg_prior_month."
    },
    {
      "name": "recent_month_weekly_avg_cte",
      "purpose": "Compute the recent-month weekly average mg without duplicating rows.",
      "logic": "Aggregate recent_month_weekly_sums_cte to a single row: AVG(derived:weekly_sum_rytelo_total_mg_recent_month) as derived:recent_month_weekly_avg_mg."
    },
    {
      "name": "prior_month_weekly_avg_cte",
      "purpose": "Compute the prior-month weekly average mg without duplicating rows.",
      "logic": "Aggregate prior_month_weekly_sums_cte to a single row: AVG(derived:weekly_sum_rytelo_total_mg_prior_month) as derived:prior_month_weekly_avg_mg."
    },
    {
      "name": "weekly_growth_cte",
      "purpose": "Compute growth percent using the two single-row weekly averages, avoiding cartesian products.",
      "logic": "Combine derived:recent_month_weekly_avg_mg and derived:prior_month_weekly_avg_mg as two scalar values (each from its own single-row CTE). Compute derived:growth_percent_weekly_avg_mg_recent_vs_prior_month = CASE WHEN prior_avg = 0 AND recent_avg > 0 THEN 100 WHEN prior_avg = 0 AND recent_avg = 0 THEN 0 ELSE ((recent_avg - prior_avg) / prior_avg) * 100 END."
    }
  ],
  "group_by": [],
  "order_by": [],
  "limit": null,
  "final_output": {
    "columns": [
      "sales_recent_month_mg",
      "sales_recent_month_sls",
      "weekly_avg_sales_recent_month_mg",
      "weekly_avg_sales_prior_month_mg",
      "growth_recent_month_vs_prior_month_mg"
    ],
    "row_granularity": "single_row"
  },
  "validation_rules": [
    "Use only data_867 for this Rytelo-only sales performance request (do not use total_sls or competitor table).",
    "Derive derived:max_date using a subquery MAX(date); do not use system date.",
    "Recent month must be the calendar month that contains derived:max_date; do not assume the current calendar month.",
    "Weekly normalization must use week_end_date; compute weekly sums within each month and then compute AVG of those weekly sums for each month.",
    "Do not compute weekly averages by CROSS JOINing weekly-sum rowsets from different months; each month’s weekly average must be computed in its own single-row aggregation before any combination.",
    "Because months can be unequal length, compute growth using the weekly averages (of weekly sums) before comparison.",
    "For growth metrics, if prior period weekly average is 0 and recent period weekly average > 0, set growth to 100%; if both are 0, set growth to 0%.",
    "All growth metrics must be expressed in percentage (%) format and must be converted to integers (no decimals) before reporting.",
    "All weekly-average outputs must be converted to integers (no decimals) before reporting.",
    "Always accompany growth with the corresponding absolute volume metric (include sales_recent_month_mg).",
    "Although default aggregation level is campus, since no campus breakdown is requested, roll up across all campuses to return a single national total row.",
